// Lightweight in-app i18n. English is the base; any missing translation falls
// back to English. Add a key to TR and translate it per language as screens
// migrate from hardcoded strings to t('key').

export type LangCode = 'en' | 'hi' | 'bn' | 'mr' | 'gu' | 'kn' | 'ta';

export type LangInfo = { code: LangCode; name: string; native: string };

/** Order shown in the language picker. English first, then by region. */
export const LANGS: LangInfo[] = [
  { code: 'en', name: 'English', native: 'English' },
  { code: 'hi', name: 'Hindi', native: 'हिन्दी' },
  { code: 'bn', name: 'Bengali', native: 'বাংলা' },
  { code: 'mr', name: 'Marathi', native: 'मराठी' },
  { code: 'gu', name: 'Gujarati', native: 'ગુજરાતી' },
  { code: 'kn', name: 'Kannada', native: 'ಕನ್ನಡ' },
  { code: 'ta', name: 'Tamil', native: 'தமிழ்' },
];

export const DEFAULT_LANG: LangCode = 'en';

export const langInfo = (code: LangCode): LangInfo =>
  LANGS.find((l) => l.code === code) ?? LANGS[0];

type Entry = Partial<Record<LangCode, string>> & { en: string };

