  'inbox.tabRequests': { en: 'Requests', hi: 'अनुरोध', bn: 'অনুরোধ', mr: 'विनंत्या', gu: 'વિનંતીઓ', kn: 'ವಿನಂತಿಗಳು', ta: 'கோரிக்கைகள்' },
  'inbox.deleteChatTitle': { en: 'Delete chat?', hi: 'चैट हटाएं?', bn: 'চ্যাট মুছবেন?', mr: 'गप्पा हटवायच्या?', gu: 'ચેટ કાઢી નાખવી?', kn: 'ಚಾಟ್ ಅಳಿಸಬೇಕೆ?', ta: 'அரட்டையை நீக்கவா?' },
  'inbox.deleteChatMsg': { en: 'Delete your conversation with {name}? This removes it for you.', hi: '{name} के साथ अपनी बातचीत हटाएं? यह आपके लिए इसे हटा देगा।', bn: '{name} এর সাথে আপনার কথোপকথন মুছবেন? এটি আপনার জন্য সরিয়ে দেয়।', mr: '{name} सोबतचे तुमचे संभाषण हटवायचे? हे तुमच्यासाठी ते काढून टाकेल.', gu: '{name} સાથેની તમારી વાતચીત કાઢી નાખવી? આ તમારા માટે તેને દૂર કરે છે.', kn: '{name} ಅವರೊಂದಿಗಿನ ನಿಮ್ಮ ಸಂಭಾಷಣೆಯನ್ನು ಅಳಿಸಬೇಕೆ? ಇದು ನಿಮಗಾಗಿ ಅದನ್ನು ತೆಗೆದುಹಾಕುತ್ತದೆ.', ta: '{name} உடனான உங்கள் உரையாடலை நீக்கவா? இது உங்களுக்காக அதை அகற்றும்.' },
  'inbox.noChatsTitle': { en: 'No chats yet', hi: 'अभी तक कोई चैट नहीं', bn: 'এখনও কোনো চ্যাট নেই', mr: 'अद्याप गप्पा नाहीत', gu: 'હજુ સુધી કોઈ ચેટ નથી', kn: 'ಇನ್ನೂ ಯಾವುದೇ ಚಾಟ್‌ಗಳಿಲ್ಲ', ta: 'இன்னும் அரட்டைகள் இல்லை' },
  'inbox.noChatsBody': { en: 'Messages from people you chat with show up here.', hi: 'जिन लोगों से आप चैट करते हैं उनके संदेश यहां दिखेंगे।', bn: 'আপনি যাদের সাথে চ্যাট করেন তাদের বার্তা এখানে দেখা যাবে।', mr: 'तुम्ही ज्यांच्याशी गप्पा मारता त्यांचे संदेश येथे दिसतील.', gu: 'તમે જેમની સાથે ચેટ કરો છો તેમના સંદેશા અહીં દેખાશે.', kn: 'ನೀವು ಚಾಟ್ ಮಾಡುವ ಜನರ ಸಂದೇಶಗಳು ಇಲ್ಲಿ ಕಾಣಿಸುತ್ತವೆ.', ta: 'நீங்கள் அரட்டையடிக்கும் நபர்களின் செய்திகள் இங்கே தோன்றும்.' },
  'inbox.noRequestsTitle': { en: 'No requests yet', hi: 'अभी तक कोई अनुरोध नहीं', bn: 'এখনও কোনো অনুরোধ নেই', mr: 'अद्याप विनंत्या नाहीत', gu: 'હજુ સુધી કોઈ વિનંતી નથી', kn: 'ಇನ್ನೂ ಯಾವುದೇ ವಿನಂತಿಗಳಿಲ್ಲ', ta: 'இன்னும் கோரிக்கைகள் இல்லை' },
  'inbox.noRequestsBody': { en: 'When someone wants one of your listings, it shows up here to accept or reject.', hi: 'जब कोई आपकी किसी लिस्टिंग को चाहता है, तो वह यहां स्वीकार या अस्वीकार करने के लिए दिखती है।', bn: 'যখন কেউ আপনার কোনো তালিকা চায়, তখন এটি গ্রহণ বা প্রত্যাখ্যান করতে এখানে দেখা যায়।', mr: 'जेव्हा कोणाला तुमची एखादी यादी हवी असते, तेव्हा ती स्वीकारण्यासाठी किंवा नाकारण्यासाठी येथे दिसते.', gu: 'જ્યારે કોઈને તમારી કોઈ યાદી જોઈએ છે, ત્યારે તે સ્વીકારવા કે નકારવા માટે અહીં દેખાય છે.', kn: 'ಯಾರಾದರೂ ನಿಮ್ಮ ಪಟ್ಟಿಯೊಂದನ್ನು ಬಯಸಿದಾಗ, ಅದು ಸ್ವೀಕರಿಸಲು ಅಥವಾ ತಿರಸ್ಕರಿಸಲು ಇಲ್ಲಿ ಕಾಣಿಸುತ್ತದೆ.', ta: 'யாராவது உங்கள் பட்டியல்களில் ஒன்றை விரும்பினால், அது ஏற்க அல்லது நிராகரிக்க இங்கே தோன்றும்.' },
