  'impact.recentHandoffs': { en: 'Recent hand-offs', hi: 'हाल के हस्तांतरण', bn: 'সাম্প্রতিক হস্তান্তর', mr: 'अलीकडील हस्तांतरण', gu: 'તાજેતરના હેન્ડ-ઑફ', kn: 'ಇತ್ತೀಚಿನ ಹಸ್ತಾಂತರಗಳು', ta: 'சமீபத்திய ஒப்படைப்புகள்' },
