  'impact.reviews': { en: 'Reviews', hi: 'समीक्षाएं', bn: 'পর্যালোচনা', mr: 'पुनरावलोकने', gu: 'સમીક્ષાઓ', kn: 'ವಿಮರ್ಶೆಗಳು', ta: 'மதிப்புரைகள்' },
