  // ---- location ----
  'location.title': { en: 'Turn on location', hi: 'स्थान चालू करें', bn: 'অবস্থান চালু করুন', mr: 'स्थान चालू करा', gu: 'સ્થાન ચાલુ કરો', kn: 'ಸ್ಥಳವನ್ನು ಆನ್ ಮಾಡಿ', ta: 'இருப்பிடத்தை இயக்கவும்' },
  'location.body': { en: 'So we can show you free items closest to you. Your exact spot is never shared with anyone.', hi: 'ताकि हम आपको आपके सबसे नज़दीकी मुफ़्त सामान दिखा सकें। आपका सटीक स्थान कभी किसी के साथ साझा नहीं किया जाता।', bn: 'যাতে আমরা আপনার সবচেয়ে কাছের বিনামূল্যের আইটেমগুলি দেখাতে পারি। আপনার সঠিক অবস্থান কখনও কারও সাথে শেয়ার করা হয় না।', mr: 'जेणेकरून आम्ही तुम्हाला तुमच्या जवळचे मोफत सामान दाखवू शकू. तुमचे नेमके ठिकाण कधीही कोणाशीही शेअर केले जात नाही.', gu: 'જેથી અમે તમને તમારી નજીકની મફત વસ્તુઓ બતાવી શકીએ. તમારું ચોક્કસ સ્થાન ક્યારેય કોઈની સાથે શેર કરવામાં આવતું નથી.', kn: 'ಇದರಿಂದ ನಿಮ್ಮ ಹತ್ತಿರದ ಉಚಿತ ವಸ್ತುಗಳನ್ನು ತೋರಿಸಬಹುದು. ನಿಮ್ಮ ನಿಖರ ಸ್ಥಳವನ್ನು ಎಂದಿಗೂ ಯಾರೊಂದಿಗೂ ಹಂಚಿಕೊಳ್ಳುವುದಿಲ್ಲ.', ta: 'இதனால் உங்களுக்கு அருகிலுள்ள இலவசப் பொருட்களைக் காட்ட முடியும். உங்கள் சரியான இடம் யாருடனும் பகிரப்படுவதில்லை.' },
  'location.allow': { en: 'Allow location', hi: 'स्थान की अनुमति दें', bn: 'অবস্থানের অনুমতি দিন', mr: 'स्थानास परवानगी द्या', gu: 'સ્થાનની મંજૂરી આપો', kn: 'ಸ್ಥಳಕ್ಕೆ ಅನುಮತಿಸಿ', ta: 'இருப்பிடத்தை அனுமதிக்கவும்' },
  'location.notNow': { en: 'Not now', hi: 'अभी नहीं', bn: 'এখন নয়', mr: 'आता नको', gu: 'હમણાં નહીં', kn: 'ಈಗ ಬೇಡ', ta: 'இப்போது வேண்டாம்' },

